args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?lake ?lakeLabel ?depth WHERE {
  ?lake wdt:P31 wd:Q23397 ;
        wdt:P4511 ?depth .
  FILTER(?depth > 400)
  OPTIONAL { ?lake rdfs:label ?lakeLabel . FILTER(LANG(?lakeLabel) = 'en') }
}
LIMIT 100

SELECT ?lake ?depth WHERE {
  ?lake wdt:P31/wdt:P279* wd:Q23397 ;
        wdt:P4511 ?depth .
  FILTER(xsd:decimal(?depth) > 400)
  FILTER(?depth != 'N/A')
  OPTIONAL { ?lake rdfs:label ?lakeLabel . FILTER(LANG(?lakeLabel) = 'en') }
} ORDER BY DESC(?depth)
